package controllers

import javax.inject._
import play.api.mvc._
import play.api.libs.json._
import play.api.db.Database
import scala.concurrent.{ExecutionContext, Future}
import java.sql.ResultSet

case class OrderDetail(
  id: Long,
  userId: Long,
  productName: String,
  quantity: Int,
  price: BigDecimal,
  status: String,
  createdAt: String
)

object OrderDetail {
  implicit val writes: OWrites[OrderDetail] = Json.writes[OrderDetail]
}

@Singleton
class OrderController @Inject()(
  val controllerComponents: ControllerComponents,
  db: Database
)(implicit ec: ExecutionContext) extends BaseController {

  def getOrder(orderId: Long): Action[AnyContent] = Action.async { implicit request =>
    Future {
      db.withConnection { conn =>
        val stmt = conn.prepareStatement(
          """SELECT id, user_id, product_name, quantity, price, status, created_at
            |FROM orders
            |WHERE id = ?""".stripMargin
        )
        stmt.setLong(1, orderId)
        val rs: ResultSet = stmt.executeQuery()

        if (rs.next()) {
          val order = OrderDetail(
            id = rs.getLong("id"),
            userId = rs.getLong("user_id"),
            productName = rs.getString("product_name"),
            quantity = rs.getInt("quantity"),
            price = rs.getBigDecimal("price"),
            status = rs.getString("status"),
            createdAt = rs.getString("created_at")
          )
          Ok(Json.toJson(order))
        } else {
          NotFound(Json.obj("error" -> s"Order with id $orderId not found"))
        }
      }
    }
  }
}